import { get } from 'node:https';

const GITHUB_RAW = 'https://raw.githubusercontent.com';

/**
 * Fetches raw text from a URL over HTTPS.
 */
function fetchRaw(url) {
  return new Promise((resolve, reject) => {
    get(url, (res) => {
      if (res.statusCode === 301 || res.statusCode === 302) {
        return fetchRaw(res.headers.location).then(resolve).catch(reject);
      }
      if (res.statusCode !== 200) {
        return reject(new Error(`HTTP ${res.statusCode} fetching ${url}`));
      }
      let body = '';
      res.on('data', (chunk) => { body += chunk; });
      res.on('end', () => resolve(body));
    }).on('error', reject);
  });
}

/**
 * Fetches skill content from GitHub.
 * Each skill must have { skillName, repo } where repo = 'owner/repo'.
 * Returns: [{ path: absolute_path, content: string }]
 *
 * The caller is responsible for resolving the install path using the agent's installDir.
 * This function only returns { skillName, content } — path resolution happens in index.mjs.
 */
export async function fetchSkillContents(skills, targetDir, agentInstallDir, fileTemplate = '{skillName}.md') {
  const results = [];

  for (const { skillName, repo, subdir } of skills) {
    if (!repo) throw new Error(`Skill "${skillName}" has no repo field`);

    const skillPath = subdir ? `${subdir}/${skillName}/SKILL.md` : `${skillName}/SKILL.md`;
    const url = `${GITHUB_RAW}/${repo}/HEAD/${skillPath}`;
    const content = await fetchRaw(url);
    const fileName = fileTemplate.replace('{skillName}', skillName);
    const path = `${targetDir}/${agentInstallDir}/${fileName}`;

    results.push({ path, content });
  }

  return results;
}

/**
 * No-op: skill listing is now handled by the skills-map locally.
 * Kept for API compatibility.
 */
export async function listSkills() {
  return [];
}
